import { afterEach, expect, test, vi } from "vitest";

const supabaseAuthMock = { signInWithOAuth: vi.fn<() => Promise<void>>() };
const mockAuthMock = { signInWithOAuth: vi.fn<() => Promise<void>>() };

vi.mock("./supabase-auth", () => ({
  createSupabaseAuth: () => supabaseAuthMock,
}));

vi.mock("./mock-auth", () => ({
  createMockAuth: () => mockAuthMock,
}));

afterEach(() => {
  vi.unstubAllEnvs();
});

test("NEXT_PUBLIC_AUTH_MODE 未設定の場合は Supabase 実装を返す", async () => {
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", undefined);
  const { createAuth } = await import("./index");

  const auth = createAuth();

  expect(auth).toBe(supabaseAuthMock);
});

test("NEXT_PUBLIC_AUTH_MODE=supabase の場合は Supabase 実装を返す", async () => {
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", "supabase");
  const { createAuth } = await import("./index");

  const auth = createAuth();

  expect(auth).toBe(supabaseAuthMock);
});

test("NEXT_PUBLIC_AUTH_MODE=mock かつ NODE_ENV!=production の場合は Mock 実装を返す", async () => {
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", "mock");
  vi.stubEnv("NODE_ENV", "development");
  const { createAuth } = await import("./index");

  const auth = createAuth();

  expect(auth).toBe(mockAuthMock);
});

test("NEXT_PUBLIC_AUTH_MODE=mock かつ NODE_ENV=production の場合は throw する", async () => {
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", "mock");
  vi.stubEnv("NODE_ENV", "production");
  const { createAuth } = await import("./index");

  expect(() => createAuth()).toThrow(/production/);
});

