import { expect, test as base, vi } from "vitest";
import { createSupabaseAuth } from "./supabase-auth";

const signInWithOAuthMock =
  vi.fn<
    (input: {
      provider: string;
      options?: { redirectTo?: string };
    }) => Promise<unknown>
  >();

vi.mock("@/lib/supabase/client", () => ({
  createClient: () => ({
    auth: { signInWithOAuth: signInWithOAuthMock },
  }),
}));

const test = base.extend<{ auth: ReturnType<typeof createSupabaseAuth> }>({
  auth: async ({}, provide) => {
    signInWithOAuthMock.mockReset();
    signInWithOAuthMock.mockResolvedValue({});
    vi.stubGlobal("location", { origin: "http://localhost:60000" });
    await provide(createSupabaseAuth());
    vi.unstubAllGlobals();
  },
});

test("redirectTo を指定しない場合は location.origin/auth/callback がデフォルト", async ({
  auth,
}) => {
  await auth.signInWithOAuth({ provider: "google" });

  expect(signInWithOAuthMock).toHaveBeenCalledWith({
    provider: "google",
    options: { redirectTo: "http://localhost:60000/auth/callback" },
  });
});

test("redirectTo を指定した場合はそれが使われる", async ({ auth }) => {
  await auth.signInWithOAuth({
    provider: "google",
    redirectTo: "https://example.com/callback",
  });

  expect(signInWithOAuthMock).toHaveBeenCalledWith({
    provider: "google",
    options: { redirectTo: "https://example.com/callback" },
  });
});

