import { afterEach, expect, test as base } from "vitest";
import { createClient } from "@supabase/supabase-js";
import { seedUser } from "./data-seeding";

const test = base.extend<{ uniqueEmail: string }>({
  uniqueEmail: async ({}, provide) => {
    const id = crypto.randomUUID();
    await provide(`seed-${id}@test.local`);
  },
});

afterEach(async () => {
  // 各テストで作成したユーザーを掃除する
  const url =
    process.env.NEXT_PUBLIC_SUPABASE_URL ?? process.env.SUPABASE_URL;
  const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
  if (!url || !serviceRoleKey) return;
  const admin = createClient(url, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });
  const { data } = await admin.auth.admin.listUsers({ perPage: 1000 });
  for (const user of data.users) {
    if (user.email?.startsWith("seed-")) {
      await admin.auth.admin.deleteUser(user.id);
    }
  }
});

test("初回呼び出しでユーザーが作成される", async ({ uniqueEmail }) => {
  const result = await seedUser({ email: uniqueEmail, password: "password123" });

  expect(result.userId).toMatch(/^[\da-f-]{36}$/);
});

test("同じ email で再呼び出ししても同じ userId を返す（冪等性）", async ({
  uniqueEmail,
}) => {
  const first = await seedUser({ email: uniqueEmail, password: "password123" });
  const second = await seedUser({
    email: uniqueEmail,
    password: "password123",
  });

  expect(second.userId).toBe(first.userId);
});

