import { afterEach, expect } from "vitest";
import { createClient } from "@supabase/supabase-js";
import { test } from "./auth-fixture";

afterEach(async () => {
  const url =
    process.env.NEXT_PUBLIC_SUPABASE_URL ?? process.env.SUPABASE_URL;
  const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
  if (!url || !serviceRoleKey) return;
  const admin = createClient(url, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });
  const { data } = await admin.auth.admin.listUsers({ perPage: 1000 });
  for (const user of data.users) {
    if (user.email?.startsWith("fixture-")) {
      await admin.auth.admin.deleteUser(user.id);
    }
  }
});

test("loggedInUser fixture から userId と accessToken が取得できる", ({
  loggedInUser,
}) => {
  expect(loggedInUser.userId).toMatch(/^[\da-f-]{36}$/);
  expect(loggedInUser.accessToken).toMatch(/^[\w-]+\.[\w-]+\.[\w-]+$/);
});

test("loggedInUser の accessToken は Supabase の getUser で本人として認証できる", async ({
  loggedInUser,
}) => {
  const url =
    process.env.NEXT_PUBLIC_SUPABASE_URL ?? process.env.SUPABASE_URL;
  const anonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  const client = createClient(url!, anonKey!, {
    auth: { persistSession: false, autoRefreshToken: false },
    global: {
      headers: { Authorization: `Bearer ${loggedInUser.accessToken}` },
    },
  });
  const { data, error } = await client.auth.getUser(loggedInUser.accessToken);

  expect(error).toBeNull();
  expect(data.user?.id).toBe(loggedInUser.userId);
});

