const authModeSchema = v.optional(
  v.picklist(["supabase", "mock"]),
  "supabase",
);

export type AuthMode = v.InferOutput<typeof authModeSchema>;

export function getAuthMode(): AuthMode {
  return v.parse(authModeSchema, process.env.NEXT_PUBLIC_AUTH_MODE);
}

const mockAuthConfigSchema = v.object({
  email: v.pipe(v.string(), v.email()),
  password: v.pipe(v.string(), v.minLength(6)),
});

export type MockAuthConfig = v.InferOutput<typeof mockAuthConfigSchema>;

export function getMockAuthConfig(): MockAuthConfig {
  return v.parse(mockAuthConfigSchema, {
    email: process.env.NEXT_PUBLIC_MOCK_AUTH_EMAIL,
    password: process.env.NEXT_PUBLIC_MOCK_AUTH_PASSWORD,
  });
}

