import { getMockAuthConfig } from "./config";
import { redirectHome } from "./redirect";
import type { Auth } from "./types";

export function createMockAuth(): Auth {
  return {
    async signInWithOAuth(): Promise<void> {
      const { email, password } = getMockAuthConfig();
      const supabase = createClient();
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });
      if (error) {
        throw new Error(`Mock auth failed: ${error.message}`);
      }
      redirectHome();
    },
  };
}

