import { getAuthMode } from "./config";
import { createMockAuth } from "./mock-auth";
import { createSupabaseAuth } from "./supabase-auth";
import type { Auth } from "./types";

export type { Auth, SignInWithOAuthInput } from "./types";

export function createAuth(): Auth {
  const mode = getAuthMode();
  if (mode === "mock") {
    if (process.env.NODE_ENV === "production") {
      throw new Error(
        "NEXT_PUBLIC_AUTH_MODE=mock is not allowed in production builds.",
      );
    }
    return createMockAuth();
  }
  return createSupabaseAuth();
}

