import { getAuthMode, getMockAuthConfig } from "./config";

afterEach(() => {
  vi.unstubAllEnvs();
});

test("NEXT_PUBLIC_AUTH_MODE 未設定の場合は supabase を返す", () => {
  // eslint-disable-next-line unicorn/no-useless-undefined
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", undefined);

  expect(getAuthMode()).toBe("supabase");
});

test("NEXT_PUBLIC_AUTH_MODE=mock の場合は mock を返す", () => {
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", "mock");

  expect(getAuthMode()).toBe("mock");
});

test("NEXT_PUBLIC_AUTH_MODE が不正な値の場合は throw する", () => {
  vi.stubEnv("NEXT_PUBLIC_AUTH_MODE", "invalid-mode");

  expect(() => getAuthMode()).toThrow();
});

test("getMockAuthConfig: email/password が揃っていれば値を返す", () => {
  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_EMAIL", "user@example.com");
  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_PASSWORD", "secret123");

  expect(getMockAuthConfig()).toEqual({
    email: "user@example.com",
    password: "secret123",
  });
});

test("getMockAuthConfig: email が無効なら throw する", () => {
  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_EMAIL", "not-an-email");
  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_PASSWORD", "secret123");

  expect(() => getMockAuthConfig()).toThrow();
});

test("getMockAuthConfig: password が短すぎたら throw する", () => {
  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_EMAIL", "user@example.com");
  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_PASSWORD", "x");

  expect(() => getMockAuthConfig()).toThrow();
});

