import * as v from "valibot";

export const AUTH_MODE = {
  supabase: "supabase",
  mock: "mock",
} as const;

export type AuthMode = (typeof AUTH_MODE)[keyof typeof AUTH_MODE];

const authModeSchema = v.optional(
  v.picklist([AUTH_MODE.supabase, AUTH_MODE.mock]),
  AUTH_MODE.supabase,
);

export function getAuthMode(): AuthMode {
  return v.parse(authModeSchema, process.env.NEXT_PUBLIC_AUTH_MODE);
}

const mockAuthConfigSchema = v.object({
  email: v.pipe(v.string(), v.email()),
  password: v.pipe(v.string(), v.minLength(6)),
});

export type MockAuthConfig = v.InferOutput<typeof mockAuthConfigSchema>;

export function getMockAuthConfig(): MockAuthConfig {
  return v.parse(mockAuthConfigSchema, {
    email: process.env.NEXT_PUBLIC_MOCK_AUTH_EMAIL,
    password: process.env.NEXT_PUBLIC_MOCK_AUTH_PASSWORD,
  });
}

import type { SupabaseClient } from "@supabase/supabase-js";
import { AUTH_MODE, getAuthMode } from "./config";
import { createMockAuth } from "./mock-auth";
import { createSupabaseAuth } from "./supabase-auth";
import type { Auth } from "./types";

export type { Auth, SignInWithOAuthInput } from "./types";

export function createAuth(supabase: SupabaseClient): Auth {
  const mode = getAuthMode();
  if (mode === AUTH_MODE.mock) {
    if (process.env.NODE_ENV === "production") {
      throw new Error(
        "NEXT_PUBLIC_AUTH_MODE=mock is not allowed in production builds.",
      );
    }
    return createMockAuth(supabase);
  }
  return createSupabaseAuth(supabase);
}

