import type { SupabaseClient } from "@supabase/supabase-js";
import { expect, test as base, vi } from "vitest";
import { createMockAuth } from "./mock-auth";

const signInWithPasswordMock =
  vi.fn<
    (input: {
      email: string;
      password: string;
    }) => Promise<{ error: { message: string } | null }>
  >();
const redirectHomeMock = vi.fn<() => void>();

const fakeSupabase = {
  auth: { signInWithPassword: signInWithPasswordMock },
} as unknown as SupabaseClient;

vi.mock("./redirect", () => ({
  redirectHome: () => redirectHomeMock(),
}));

const test = base.extend<{ auth: ReturnType<typeof createMockAuth> }>({
  auth: async ({}, provide) => {
    signInWithPasswordMock.mockReset();
    redirectHomeMock.mockReset();
    await provide(
      createMockAuth(fakeSupabase, {
        email: "mock@example.com",
        password: "mock-password",
      }),
    );
  },
});

test("signInWithPassword が成功した場合 redirectHome を呼ぶ", async ({
  auth,
}) => {
  signInWithPasswordMock.mockResolvedValue({ error: null });

  await auth.signInWithOAuth({ provider: "google" });

  expect(signInWithPasswordMock).toHaveBeenCalledWith({
    email: "mock@example.com",
    password: "mock-password",
  });
  expect(redirectHomeMock).toHaveBeenCalledOnce();
});

test("signInWithPassword がエラーを返した場合 throw して redirectHome は呼ばれない", async ({
  auth,
}) => {
  signInWithPasswordMock.mockResolvedValue({ error: { message: "invalid" } });

  await expect(auth.signInWithOAuth({ provider: "google" })).rejects.toThrow(
    /invalid/,
  );
  expect(redirectHomeMock).not.toHaveBeenCalled();
});

