import { createClient } from "@supabase/supabase-js";

const url =
  process.env.NEXT_PUBLIC_SUPABASE_URL ??
  process.env.SUPABASE_URL ??
  "http://127.0.0.1:54321";
const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
if (!serviceRoleKey) {
  throw new Error("SUPABASE_SERVICE_ROLE_KEY が設定されている必要があります。");
}

const email = process.env.NEXT_PUBLIC_MOCK_AUTH_EMAIL ?? "test@example.com";
const password = process.env.NEXT_PUBLIC_MOCK_AUTH_PASSWORD ?? "password123";

const admin = createClient(url, serviceRoleKey, {
  auth: { persistSession: false, autoRefreshToken: false },
});

const { data, error } = await admin.auth.admin.createUser({
  email,
  password,
  email_confirm: true,
});

if (!error && data.user) {
  console.log(`Seeded user: ${email} (${data.user.id})`);
} else if (error && /already|exists|registered/i.test(error.message)) {
  const { data: list, error: listError } = await admin.auth.admin.listUsers({
    perPage: 1000,
  });
  if (listError) throw listError;
  const existing = list.users.find((u) => u.email === email);
  console.log(`User already exists: ${email} (${existing?.id ?? "unknown"})`);
} else {
  throw error ?? new Error("createUser が user を返しませんでした");
}

