import type { SupabaseClient } from "@supabase/supabase-js";
import { afterEach, expect, test, vi } from "vitest";
import type { AuthConfig } from "./config";

const supabaseAuthMock = { signInWithOAuth: vi.fn<() => Promise<void>>() };
const mockAuthMock = { signInWithOAuth: vi.fn<() => Promise<void>>() };
const getAuthConfigMock = vi.fn<() => AuthConfig>();

vi.mock("./config", () => ({
  getAuthConfig: () => getAuthConfigMock(),
}));

vi.mock("./supabase-auth", () => ({
  createSupabaseAuth: () => supabaseAuthMock,
}));

vi.mock("./mock-auth", () => ({
  createMockAuth: () => mockAuthMock,
}));

const fakeSupabase = {} as unknown as SupabaseClient;

afterEach(() => {
  vi.unstubAllEnvs();
  getAuthConfigMock.mockReset();
});

test("isMocked: false の場合は Supabase 実装を返す", async () => {
  getAuthConfigMock.mockReturnValue({ isMocked: false });
  const { createAuth } = await import("./index");

  const auth = createAuth(fakeSupabase);

  expect(auth).toBe(supabaseAuthMock);
});

test("isMocked: true の場合は Mock 実装を返す", async () => {
  getAuthConfigMock.mockReturnValue({
    isMocked: true,
    email: "test@example.com",
    password: "password123",
  });
  const { createAuth } = await import("./index");

  const auth = createAuth(fakeSupabase);

  expect(auth).toBe(mockAuthMock);
});

