const getAuthConfigMock = vi.fn<() => AuthConfig>();

vi.mock("./config", () => ({
  getAuthConfig: () => getAuthConfigMock(),
}));

vi.mock("./supabase-auth", () => ({
  createSupabaseAuth: () => supabaseAuthMock,
}));

vi.mock("./mock-auth", () => ({
  createMockAuth: () => mockAuthMock,
}));

const fakeSupabase = {} as unknown as SupabaseClient;

const test = base.extend<{ createAuth: typeof createAuth }>({
  createAuth: async ({}, provide) => {
    getAuthConfigMock.mockReset();
    await provide(createAuth);
  },
});

test("isMocked: false の場合は Supabase 実装を返す", ({ createAuth }) => {
